class TextEditor {
public:
    string text;
    int cursor;

    TextEditor() {
        cursor = 0;
    }

    void addText(string s) {
        text.insert(cursor, s);
        cursor += s.length();
    }

    int deleteText(int k) {
        int deleted = min(k, cursor);
        text.erase(cursor - deleted, deleted);
        cursor -= deleted;
        return deleted;
    }

    string cursorLeft(int k) {
        cursor = max(0, cursor - k);
        int len = min(10, cursor);
        return text.substr(cursor - len, len);
    }

    string cursorRight(int k) {
        cursor = min((int)text.length(), cursor + k);
        int len = min(10, cursor);
        return text.substr(cursor - len, len);
    }
};
```
